import{_ as e,o as t,c as a,O as r}from"./chunks/framework.bdcb0ee1.js";const p=JSON.parse('{"title":"Board Menu","description":"","frontmatter":{},"headers":[],"relativePath":"administration/content/board-menu.md","filePath":"administration/content/board-menu.md","lastUpdated":1773166892000}'),n={name:"administration/content/board-menu.md"},o=r('<h1 id="board-menu" tabindex="-1">Board Menu <a class="header-anchor" href="#board-menu" aria-label="Permalink to &quot;Board Menu&quot;">​</a></h1><p>The board menu controls the navigation links shown at the top of your board. You can add, remove and reorder items to customise the navigation experience for your users. Menu management is found under the <strong>Content</strong> navigation group in the Admin CP.</p><img width="1946" height="936" alt="image" src="https://github.com/user-attachments/assets/b07b2ba8-8a47-474d-ac91-95e0676fa73c"><nav class="table-of-contents"><ul><li><a href="#default-menu-items">Default menu items</a></li><li><a href="#menu-item-types">Menu item types</a><ul><li><a href="#feature">Feature</a></li><li><a href="#external">External</a></li><li><a href="#resource">Resource</a></li></ul></li><li><a href="#creating-a-menu-item">Creating a menu item</a></li><li><a href="#reordering-menu-items">Reordering menu items</a></li><li><a href="#editing-and-deleting-menu-items">Editing and deleting menu items</a></li></ul></nav><h2 id="default-menu-items" tabindex="-1">Default menu items <a class="header-anchor" href="#default-menu-items" aria-label="Permalink to &quot;Default menu items&quot;">​</a></h2><p>Every new board is created with a set of default menu items:</p><table><thead><tr><th>Item</th><th>Feature</th></tr></thead><tbody><tr><td>Home</td><td><code>home</code></td></tr><tr><td>What&#39;s New</td><td><code>whats-new</code></td></tr><tr><td>Members</td><td><code>members</code></td></tr><tr><td>Search</td><td><code>search</code></td></tr><tr><td>Staff</td><td><code>staff</code></td></tr><tr><td>Help</td><td><code>help</code></td></tr></tbody></table><p>You can remove, reorder or add to these at any time.</p><h2 id="menu-item-types" tabindex="-1">Menu item types <a class="header-anchor" href="#menu-item-types" aria-label="Permalink to &quot;Menu item types&quot;">​</a></h2><p>There are three types of menu item you can create:</p><h3 id="feature" tabindex="-1">Feature <a class="header-anchor" href="#feature" aria-label="Permalink to &quot;Feature&quot;">​</a></h3><p>Links to a built-in board feature. The available features are:</p><ul><li><strong>Home</strong> — the board index</li><li><strong>What&#39;s New</strong> — recently active topics</li><li><strong>Members</strong> — the member list</li><li><strong>Search</strong> — the search page</li><li><strong>Staff</strong> — the staff page</li><li><strong>Active Topics</strong> — topics with recent activity</li><li><strong>Top Posters</strong> — leaderboard of top contributors</li><li><strong>Help</strong> — the help section</li></ul><h3 id="external" tabindex="-1">External <a class="header-anchor" href="#external" aria-label="Permalink to &quot;External&quot;">​</a></h3><p>Links to any external URL. Use this to point users to your main website, social media pages or any other off-board destination. The URL must include the scheme (e.g. <code>https://</code>).</p><h3 id="resource" tabindex="-1">Resource <a class="header-anchor" href="#resource" aria-label="Permalink to &quot;Resource&quot;">​</a></h3><p>Links to a <a href="/administration/content/pages.html">Custom Page</a> on your board. When you select this type, choose from your existing pages. This creates a polymorphic link — if the page is later deleted, the menu item is also removed.</p><blockquote><p>Note: You can also add pages to the menu automatically by enabling <strong>Show in Menu</strong> when editing a custom page.</p></blockquote><h2 id="creating-a-menu-item" tabindex="-1">Creating a menu item <a class="header-anchor" href="#creating-a-menu-item" aria-label="Permalink to &quot;Creating a menu item&quot;">​</a></h2><p>Click <strong>Create Menu Item</strong> and fill in:</p><ul><li><strong>Title</strong> — the label displayed in the navigation bar.</li><li><strong>Type</strong> — choose from Feature, External or Resource.</li><li>Depending on the type, you will be asked for a <strong>feature</strong>, <strong>URL</strong> or <strong>page</strong>.</li><li><strong>Sort Order</strong> — controls the position in the navigation bar (lower numbers appear first).</li></ul><img width="1937" height="674" alt="image" src="https://github.com/user-attachments/assets/da207c96-2a09-498c-beff-8e91eb52f2e7"><h2 id="reordering-menu-items" tabindex="-1">Reordering menu items <a class="header-anchor" href="#reordering-menu-items" aria-label="Permalink to &quot;Reordering menu items&quot;">​</a></h2><p>Adjust the <strong>Sort Order</strong> value on each item to control the display order. Items are sorted in ascending order, so an item with sort order <code>0</code> appears before one with sort order <code>5</code>.</p><h2 id="editing-and-deleting-menu-items" tabindex="-1">Editing and deleting menu items <a class="header-anchor" href="#editing-and-deleting-menu-items" aria-label="Permalink to &quot;Editing and deleting menu items&quot;">​</a></h2><p>Click on any menu item to edit it. To remove an item from the navigation, delete it from the list. Deleting a menu item does not delete the underlying page or feature — it only removes the navigation link.</p>',26),i=[o];function s(d,l,m,u,h,c){return t(),a("div",null,i)}const f=e(n,[["render",s]]);export{p as __pageData,f as default};
